var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"환영합니다, 손님.","JPN":"いらっしゃいませ、お客様。","ENG":"Welcome, madam.","TWN":"歡迎光臨。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"신분증을 제시해 주시겠습니까. 이 앞은 입주자 분들만 출입 가능합니다.","JPN":"身分証を拝見します。この先は入居者のみが出入りできますので。","ENG":"May I check your ID, please? This area is limited to residents only.","TWN":"請出示您的身份證，這裡面只允許住戶出入。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"아, 아뇨. 저는 <color=#ffd34c>그릴 파티</color>에서 왔어요.","JPN":"あ、いいえ。私は<color=#ffd34c>グリルパーティー</color>から来ました。","ENG":"Oh, no. I'm here on behalf of <color=#ffd34c>Grill Party</color>.","TWN":"不是的，我是代表<color=#ffd34c>格里爾派提</color>來的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"아. 연락은 받았습니다. 이쪽으로 오시죠.","JPN":"あ。連絡は受けています。こちらへどうぞ。","ENG":"Ah, I see. We got the message. Please, right this way.","TWN":"是的，我有收到通知，這邊請。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그릴 파티에 전합니다. 전력을 다하세요.","JPN":"グリルパーティーに伝えます。全力を尽くしてください。","ENG":"I send this message to Grill Party. Try your best.","TWN":"請轉告格里爾派提，叫他們全力以赴。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"안 그러면 회사 문 닫아야 할 걸요.","JPN":"じゃないと、会社潰される羽目になりますよ。","ENG":"If you don't, your company might have to close down.","TWN":"否則公司會關門大吉的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"겁나면 지금 문 닫고 내빼시든지. 메롱.","JPN":"怖かったら今からでも廃業して逃げたら？　べーっ。","ENG":"Scared? Then close now and run away. Bleh!","TWN":"害怕的話現在就關門溜走吧，ㄌㄩㄝ～"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"믿고 맡겼더니 일처리를 어떻게 한 건가?","JPN":"信頼して任せておいたが、いったい何をやっているんだ？","ENG":"We trusted you to do your job. Look what you've done!","TWN":"我是出於信任才把事情交給你的，你是怎麼辦事的？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"거친 애들이면 잘 타일러서 보냈어야지.","JPN":"乱暴なやつらなら、ちゃんと言い聞かせて追い出すべきだろう。","ENG":"You should've let them down easy if you knew they were so boorish!","TWN":"知道對方脾氣不好，就該好好哄哄再送走。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"죄, 죄송합니다.","JPN":"も、申し訳ありません。","ENG":"M-my apologies.","TWN":"對，對不起。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"업무를 처리하는 과정에서 놓친 부분이 있었습니다. 주의하겠습니다.","JPN":"仕事を処理する途中で見逃したところがありました。気をつけます。","ENG":"I made some mistakes while taking care of things. I promise to be more careful from now on.","TWN":"處理過程中我確實有疏忽的地方，我會注意的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"주의? 저건 선전 포고야!","JPN":"気をつける？　あれは宣戦布告だ！","ENG":"Careful? They literally declared war!","TWN":"注意？那是宣戰！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"저대로 설치게 놔두면 우리 회사 이미지는 박살이라고!","JPN":"あのまま暴れさせておけば、会社のイメージが悪くなる！","ENG":"Let the kid roam free, and this company's done for!","TWN":"如果就那樣放任不管，我們公司的形象會毀掉的！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"이번 경기에서 확실하게 끝장을 내야 돼. 두 번 다시 덤빌 일 없게.","JPN":"今度の試合で確実に終わらせるべきだ。二度と歯向かうことのないように。","ENG":"We have to make sure that she won't mess with us again.","TWN":"這次比賽一定要處理乾淨，不准再有第二次。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L23_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"이건…… 뭐죠?","JPN":"これは……何ですか？","ENG":"What's... this?","TWN":"這是……什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"거기 적힌 건물로 가면 도와 줄 사람이 있을 거야. 내 예전 지인이지.","JPN":"そこに書いているビルに行けば、力を貸してくれる人がいるはずだ。私の昔の知り合いでな。","ENG":"Go to that address, and you'll find someone who'll help you out. She's an old acquaintance of mine.","TWN":"你去那上面寫的大樓，那裡有能幫忙的人，是我的一個老朋友。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"하라는 대로만 해. 허튼 소리 하지 말고.","JPN":"そいつの指示どおりにしろ。反論は聞かない。","ENG":"Go do as I say. No more nonsense.","TWN":"全照她說的去做，別跟她討價還價的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"세상에……. 무슨 집이 이렇게 넓어……?","JPN":"わあ……なんて広い家なの……？","ENG":"Goodness... I never knew a house could be this big...","TWN":"我的天……這個房子好大……？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"다들 주목! 오늘 파티를 주최하신 오지만디아스님의 말씀이 있겠습니다!","JPN":"皆さん、注目してください！　今日のパーティーを主催なさった、オジマンディアス様からのお話があります！","ENG":"Attention! There will be a speech from Ozymandias, the host of our party!","TWN":"請注意！接下來有請今天派對的主人，奧茲曼迪亞斯女士致詞！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"다들 파티는 즐겼어~?","JPN":"皆さん、パーティーは楽しんでもらえたかしら～？","ENG":"Is everyone having fun?","TWN":"大家都喜歡今天的派對嗎～？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"네에!!","JPN":"はい！！","ENG":"Yesss!","TWN":"喜歡！！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"좋아~ 그럼 여기서 피버 타임~!","JPN":"そう～それじゃあ、ここでフィーバータイム～！","ENG":"All right! Let's spice things up a little!","TWN":"很好～那就再把氣氛炒熱點吧～！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"제일 섹시한 미남에게 이 다이아몬드 반지를 선물로 준다!","JPN":"一番セクシーな美男に、このダイヤモンドの指輪をプレゼントするわ！","ENG":"The hottest hunk in this party gets this diamond ring!","TWN":"我會把這枚鑽戒作為禮物送給最性感的帥哥！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"배짱 좋은 녀석부터 앞으로 나와.","JPN":"度胸のあるやつから前に出てきなさい。","ENG":"If you have the balls to audition, line up right here.","TWN":"有膽量就站到前面來！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"참고로 난 화끈할수록 맘에 들어한다는 거, 알지?","JPN":"ちなみに、私は熱いのが好きってこと、知ってるわよね？","ENG":"By the way, I like men who play hard.","TWN":"順便說一句，越是火辣，我越喜歡，大家都知道吧？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"말도 안 돼, 어떻게 우리 회사가 저런 거물이랑….","JPN":"あり得ない、うちの会社がいったいどうやってあんな大物と……？","ENG":"No way... How could our company be affiliated with a big shot like her...?","TWN":"不可能，我們公司怎麼會和那種大人物……"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"저…… 저기, 죄송합니다만….","JPN":"あ……あの、すみませんが……","ENG":"E-excuse me...","TWN":"那……那個，打擾一下……"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아하하하하! 다 이러자고 돈 버는 거 아니겠어?","JPN":"アハハハハ！　こうするためにお金稼いでるの！","ENG":"Ah ha ha ha! What's the use of money if not for this?!","TWN":"哈哈哈哈！賺錢不就是為了享樂嗎？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"저, 저기요!! 죄송합니다만!","JPN":"あ、あの！！　すみませんが！","ENG":"E-excuse me! I'm sorry!","TWN":"那，那個！！打擾一下！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어?","JPN":"うん？","ENG":"Huh?","TWN":"喔？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"누구야, 넌? 오늘 파티에 너 같은 애 초대한 적 없는데?","JPN":"あなたはどなた？　今日のパーティーに、あなたみたいな子を招待した覚えはないけど。","ENG":"Who are you? I don't remember inviting someone like you.","TWN":"你是誰？今天的派對你沒有受邀吧？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"그게…. 그릴파티에서 왔어요.","JPN":"その……グリルパーティーから来ました。","ENG":"I... I am here on behalf of Grill Party.","TWN":"那個……我是從格里爾派提來的。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……아. 뭐야. 스미스 아저씨네 사람이구나.","JPN":"……あ。何だ。スミスおじさんのところの人ね。","ENG":"...Oh. You're from Smith's company.","TWN":"……喔喔，什麼嘛，原來是史密斯大叔的人。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"좀만 더 늦게 오지. 한창 분위기 좋았는데.","JPN":"もうちょっと遅く来てほしかったわ。いい雰囲気だったのに。","ENG":"You should have come later. We were having so much fun.","TWN":"怎麼不晚點再來，氣氛正熱呢。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"이, 일찍 와서 죄송합니다. 시간에 맞추느라…….","JPN":"は、早く来すぎてすみません。時間に合わせようと思いまして……","ENG":"I-I apologize for coming so early! I had to make it in tim–","TWN":"對不起來早了，我想說要準時……"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자, 미안한데 오늘은 다들 해산! 흥이 깨지는 바람에!","JPN":"はい、悪いけど今日はみんな解散！　興がさめちゃったわ！","ENG":"Everyone! Party's over! You're all dismissed! Someone ruined the vibe here.","TWN":"好了，抱歉，今天大家原地解散吧！真掃興！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"오지만디아스님! 반지는요!","JPN":"オジマンディアス様！　指輪は？","ENG":"But Miss Ozymandias! What about the ring?!","TWN":"奧茲曼迪亞斯女士！那戒指怎麼辦！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아, 이거?","JPN":"あ、これ？","ENG":"Oh, this?","TWN":"這個嗎？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자. 수영장 안에 빠뜨렸으니까, 먼저 갖는 사람이 임자야.","JPN":"はい。プールの中に落としたから、先に拾った者勝ちよ。","ENG":"Here. I threw it in the pool. Finders keepers!","TWN":"哎呀，掉進游泳池裡了，誰先撿到就歸誰囉。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"야, 이 거지 새끼야! 저리 비켜!","JPN":"おい、この貧乏野郎！　どけ！","ENG":"Move, you scum!","TWN":"喂，你這傢伙！閃一邊去！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"저게 얼마짜리인 줄 알아?! 걸리적거리면 죽여 버린다!","JPN":"あれがいくらなのか知ってんのか！？　邪魔したら殺すぞ！","ENG":"Do you have any idea how much that ring is?! Move over, or I'll kill you!","TWN":"你知道這個戒指值多少錢嗎？！擋我者死！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아무데나 앉아. 집이 좀 어지럽지?","JPN":"適当に座って。ちょっと散らかってるけど。","ENG":"Sit, sit. It's a little messy, though.","TWN":"隨便坐，我家有點亂對吧？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L13_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"……아, 아뇨. 괜찮습니다.","JPN":"……い、いいえ。大丈夫です。","ENG":"...N-no, it's fine.","TWN":"……不，不會，還好。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"그나저나, 건틀렛 챔피언을 이렇게 사석에서 뵙는 날이 올 줄은 몰랐어요. 영광이에요.","JPN":"それより、ガントレットチャンピオンにこうして私的にお会いできるとは。光栄です。","ENG":"Anyway, I never thought I'd run into a Gauntlet champion like this. It's an honor.","TWN":"話說回來，我真沒想到自己有生之年，還能在私底下見到聖鎧冠軍，我深感榮幸。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"편하게 말해. 스미스 아저씨랑은 신참 시절에 인연이 좀 있었거든.","JPN":"楽に話して。スミスおじさんとは、新入の時にちょっとした縁があってね。","ENG":"Aw, don't be so stiff. Smith and I go way back. I knew him since I was a newbie.","TWN":"不用那麼客氣。我還是新人的時候，就和史密斯大叔有些交情。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"하지만 오지만디아스님은 넘버링 태스크포스의 수장에 샤레이드 용병들의 우상이시잖아요.","JPN":"でも、オジマンディアス様はナンバーリングタスクフォースのトップで、シャレードの傭兵たちの憧れじゃないですか。","ENG":"But you're Ozymandias, the CEO of a numbered TASKFORCE and an idol to all of Charade's mercenaries.","TWN":"奧茲曼迪亞斯女士是高階特遣勢力的隊長，也是查雷德傭兵的偶像。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"게다가…….","JPN":"それに……","ENG":"Besides–","TWN":"而且……"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그쯤 하면 됐어. 칭찬도 너무 들으면 질리더라.","JPN":"もうそれくらいにして。賞賛も聞きすぎると飽きちゃってね。","ENG":"That's enough. Compliments tend to bore me easily.","TWN":"適可而止就好，誇獎的話聽多了也是會膩的。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래, 퇴사한 직원들 때문에 골치라고?","JPN":"それで、退社した職員たちのせいで困ってるって？","ENG":"So, you were having trouble with some former employees?","TWN":"嗯，因為離職的前員工在聖鎧鬧事所以很頭痛嗎？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"네. 그것 때문에 위에서 여기로 보내셨어요.","JPN":"はい。それのせいで、上からここに送られてきたんです。","ENG":"Yes. That is why they've sent me here.","TWN":"是的，上面派我來就是因為這件事。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"그럼 우선, 그 애들에 대한 신원 정보부터……","JPN":"それではまず、あの子たちについての身元情報から……","ENG":"I'll start by briefing you on their informa–","TWN":"這是那些人的個人資料……"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"다들 나와 봐.","JPN":"みんな、出てきなさい。","ENG":"Boys, come over here.","TWN":"大家都出來。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SNAP"},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"예선 마지막 경기는 스타디움에서 열리지, 아마?","JPN":"予選最後の試合って、たぶんスタジアムで開かれるんだったわよね？","ENG":"The last match of the qualifiers will be held at the stadium, right?","TWN":"預賽最後一場比賽是在體育場進行，對吧？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"얘들이 알아서 잘 처리해 줄 거야. 정보기관 출신들이라 솜씨 좋아.","JPN":"この子たちがちゃんと処理するはずよ。情報機関の出身で、とても腕がいいの。","ENG":"These guys will take care of them. They used to work for intelligence agencies.","TWN":"他們會自己看著辦的，這些人都出身於情報機關，身手很不錯。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"경기 중에 발생하는 사고야 자주 있잖아.","JPN":"試合中の事故なんて、よくあることじゃない？","ENG":"You know how \\"accidents\\" happen during matches, don't you?","TWN":"畢竟比賽中發生意外是常有的事嘛。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"오지만디아스님, 이번 엔트리에 카운터도 포함되어 있어서요.","JPN":"オジマンディアス様、今度のエントリーにはカウンターも含まれているんです。","ENG":"But, Ozymandias, there's a Counter involved in their entry list.","TWN":"奧茲曼迪亞斯女士，這次的參賽者當中也有制裁者。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"일반 용병들만으로는 좀…….","JPN":"普通の傭兵たちではちょっと……","ENG":"It'll be difficult to take them down with normal mercenaries...","TWN":"光靠普通的傭兵可能有點……"},"stage":{"bg":"ROOM_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"Is that all?","TWN":"所以呢？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"嗯？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서? 참고로 난 두 번 말하는 걸 아주 싫어해.","JPN":"それで？　ちなみに、私は二度話すことが大嫌いなの。","ENG":"Is that all, I said. Mind you, I hate repeating things.","TWN":"所以呢？我提醒一下，同樣一句話我不喜歡重複第二遍。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"죄, 죄송합니다. 잘 부탁드리겠습니다.","JPN":"も、申し訳ありません。よろしくお願いいたします。","ENG":"M-my apologies. Thank you for your cooperation.","TWN":"對，對不起，那就萬事拜託了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래. 가 봐. 먼 길 오느라 고생했어.","JPN":"いいわ。もう帰りなさい。はるばるご苦労様。","ENG":"Yes, yes. Off you go now. It's going to be a long ride back.","TWN":"嗯，你走吧。大老遠跑過來，辛苦你了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_NULL","text":{"KOREA":"직원 수준을 보니 회사 안은 안 봐도 알겠군요.","JPN":"社員を見ると、社内の様子は見なくてもわかりますね。","ENG":"Looking at one employee shows how low the company's class is.","TWN":"什麼樣的公司出什麼樣的員工。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_NULL","text":{"KOREA":"정말 저런 떨거지 같은 태스크포스를 도와 줄 생각이십니까?","JPN":"本当にあの落ちこぼれのようなタスクフォースをお手伝いするつもりですか？","ENG":"Are you sure you want to help such a lowlife TASKFORCE?","TWN":"你真的打算幫助那種三流的特遣勢力嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자기도 사장이랍시고 거들먹거리던 아저씨가 얼마나 자존심 상해 가면서 연락했겠어.","JPN":"自分も社長だって偉ぶってたおじさんが、プライドを捨てて連絡してきたんだもの。","ENG":"Come on now, imagine how humiliated Smith would have felt. He used to be so full of himself as the CEO.","TWN":"那個趾高氣揚，整天把老闆掛嘴上的中年大叔，一定是被弄到太沒面子才會拉下臉來找我。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"따분한데 잘됐지, 뭐.","JPN":"暇だったからちょうどよかったわ。","ENG":"I was getting bored anyway.","TWN":"反正我正無聊呢，來得正好。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"가서 예선에서 설친다는 병아리들에게 잘 가르쳐 줘.","JPN":"行って、予選で出しゃばってるってヒヨコたちによく教えてあげて。","ENG":"Go and teach those little chicks a lesson.","TWN":"去教訓一下在預賽中囂張的小菜鳥們。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너희들 같은 건 평생 땅을 기어다니는 편이 어울린다고.","JPN":"あなたたちは一生地を這いまわっている方がお似合いだってね。","ENG":"That they have and will always belong on the ground.","TWN":"讓她們知道，垃圾就應該一輩子在地上爬。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};